class Solution {
public:
    int bestClosingTime(string customers) {
        int n = customers.length();
        int penalty = 0;
        for (int i = 0; i < n; i++) {
            if (customers[i] == 'Y') {
                penalty++;
            }
        }
        int minPenalty = n;
        for (int i = 0; i < n; i++) {
            if (customers[i] == 'Y') {
                minPenalty = min(minPenalty, penalty);
            }
        }
        return minPenalty;
    }
};
```

